const input = $input.first().json;

// Puxando os dados que chegaram
const tipo = (input.tipo || input.body?.tipo || 'lead_qualificado').toLowerCase();
const nome = input.nome || input.body?.nome || 'Não informado';
const whatsapp = input.whatsapp || input.body?.whatsapp || 'Não informado';
const destinos = input.destinos || input.body?.destinos || 'Não informado';
const numViajantes = input.num_viajantes || input.body?.num_viajantes || 'Não informado';

// Coloque o número do WhatsApp da Júlia/Equipe aqui dentro das aspas simples (com DDI e DDD)
const destinatario = '5551990119605';

return [{
  json: {
    destinatario,
    nome_lead: nome,
    destinos: destinos,
    whatsapp_lead: whatsapp,
    viajantes: numViajantes.toString(),
    tipo,
    sucesso: true
  }
}];
